#include <iostream>
#include <string>
#include <vector>
#include <sstream>
#include <fstream>
#include <cstdlib>
#include <algorithm>

// Helper function to extract the last integer from a string
// This function is designed to be robust to various output formats
// like "Sum: 123", "Result is -45.", "The answer is 0."
std::string extractLastInteger(const std::string& s) {
    std::string num_str;
    bool digit_started = false;
    for (int i = s.length() - 1; i >= 0; --i) {
        if (std::isdigit(s[i])) {
            num_str.push_back(s[i]);
            digit_started = true;
        } else if (s[i] == '-' && digit_started) {
            num_str.push_back(s[i]);
            break;
        } else if (digit_started) {
            break;
        }
    }
    std::reverse(num_str.begin(), num_str.end());
    return num_str.empty() ? "0" : num_str;
}

int main() {
    std::vector<std::pair<std::string, std::string>> test_cases = {
        { "123", "6" },
        { "45", "9" },
        { "0", "0" },
        { "7", "7" },
        { "-123", "-6" },
        { "-98765", "-35" }
    };

    for (size_t i = 0; i < test_cases.size(); ++i) {
        const std::string& input = test_cases[i].first;
        const std::string& expected_output_val = test_cases[i].second;

        std::string input_filename = "input_" + std::to_string(i) + ".txt";
        std::ofstream input_file(input_filename);
        if (!input_file.is_open()) {
            std::cerr << "Error: Could not open input file " << input_filename << std::endl;
            return 1;
        }
        input_file << input << std::endl;
        input_file.close();

        std::string output_filename = "output_" + std::to_string(i) + ".txt";

        std::string command = "./a.out < " + input_filename + " > " + output_filename;
        int system_result = system(command.c_str());

        if (system_result != 0) {
            std::cerr << "Error: User program execution failed for input " << input << std::endl;
        }

        std::ifstream output_file(output_filename);
        if (!output_file.is_open()) {
            std::cerr << "Error: Could not open output file " << output_filename << std::endl;
            remove(input_filename.c_str());
            return 1;
        }
        std::string line;
        std::string full_output_content;
        while (std::getline(output_file, line)) {
            full_output_content += line + "\n";
        }
        output_file.close();

        std::string actual_output_val = extractLastInteger(full_output_content);

        remove(input_filename.c_str());
        remove(output_filename.c_str());

        std::cout << "Test Case " << i + 1 << ": Input = " << input << std::endl;
        std::cout << "  Expected Sum: " << expected_output_val << std::endl;
        std::cout << "  Actual Sum:   " << actual_output_val << std::endl;

        if (actual_output_val == expected_output_val) {
            std::cout << "  Result: PASSED" << std::endl;
        } else {
            std::cout << "  Result: FAILED" << std::endl;
        }
        std::cout << "-------------------------------------" << std::endl;
    }

    return 0;
}
